import java.io.*;
import java.nio.charset.StandardCharsets;

public class ClassicIO {

    // Write bytes → chars → buffered
    public static void writeExample(String filename) throws IOException {
        // Level 1: raw bytes — FileOutputStream
        // Level 2: chars — OutputStreamWriter (bytes → chars with charset)
        // Level 3: buffered — BufferedWriter (batches writes)
        try (BufferedWriter bw = new BufferedWriter(
                new OutputStreamWriter(
                    new FileOutputStream(filename), StandardCharsets.UTF_8))) {
            bw.write("Line 1: Hello Java I/O");
            bw.newLine();  // OS-independent line separator
            bw.write("Line 2: Buffered writing");
            bw.newLine();
            bw.write("Line 3: try-with-resources closes all layers");
            // close() on BufferedWriter flushes buffer AND closes FileOutputStream
        }
    }

    // Read bytes → chars → buffered
    public static void readExample(String filename) throws IOException {
        // Decorator pattern: BufferedReader wraps InputStreamReader wraps FileInputStream
        try (BufferedReader br = new BufferedReader(
                new InputStreamReader(
                    new FileInputStream(filename), StandardCharsets.UTF_8))) {
            String line;
            int lineNum = 1;
            while ((line = br.readLine()) != null) {
                System.out.printf("%2d: %s%n", lineNum++, line);
            }
        }
    }

    // Stream lines as Stream<String> — lazy, no loading all into memory
    public static long countLinesWithStreams(String filename) throws IOException {
        try (BufferedReader br = new BufferedReader(new FileReader(filename))) {
            return br.lines().count(); // lazy stream — each line read on demand
        }
    }

    // Copy binary file — byte array buffer
    public static void copyBinary(String src, String dst) throws IOException {
        byte[] buffer = new byte[8192]; // 8KB buffer
        try (InputStream  in  = new FileInputStream(src);
             OutputStream out = new FileOutputStream(dst)) {
            int bytesRead;
            while ((bytesRead = in.read(buffer)) != -1) {
                out.write(buffer, 0, bytesRead); // write only bytes actually read
            }
        }
    }

    public static void main(String[] args) throws IOException {
        String file = "test_io.txt";
        writeExample(file);
        readExample(file);
        System.out.println("Lines: " + countLinesWithStreams(file));
        copyBinary(file, "test_io_copy.txt");
        new File(file).delete();
        new File("test_io_copy.txt").delete();
    }
}

import java.io.IOException;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.util.List;
import java.util.stream.Stream;

public class NIO2Demo {

    public static void main(String[] args) throws IOException, InterruptedException {

        // ── Path — immutable address, no I/O ───────────────────────────
        Path home    = Path.of(System.getProperty("user.home"));
        Path config  = home.resolve("config").resolve("app.properties");
        Path parent  = config.getParent();  // home/config
        Path relative = home.relativize(config); // config/app.properties
        System.out.println("Absolute: " + config.isAbsolute()); // true
        System.out.println("Filename: " + config.getFileName()); // app.properties
        System.out.println("Relative: " + relative); // config/app.properties

        // ── Files — operations ─────────────────────────────────────────
        Path tmpDir  = Files.createTempDirectory("nio2_demo");
        Path tmpFile = tmpDir.resolve("demo.txt");

        // Write
        Files.writeString(tmpFile, "Hello NIO.2\nLine 2\nLine 3");

        // Read all lines — fine for small files
        List<String> lines = Files.readAllLines(tmpFile);
        System.out.println("Lines: " + lines.size()); // 3

        // Lazy stream — efficient for large files
        try (Stream<String> lineStream = Files.lines(tmpFile)) {
            long count = lineStream.filter(l -> l.contains("Line")).count();
            System.out.println("Lines with 'Line': " + count); // 2
        } // stream (and underlying reader) closed automatically

        // Copy
        Path copy = tmpDir.resolve("demo_copy.txt");
        Files.copy(tmpFile, copy, StandardCopyOption.REPLACE_EXISTING);

        // Walk directory tree
        try (Stream<Path> walk = Files.walk(tmpDir)) {
            walk.filter(Files::isRegularFile)
                .forEach(p -> System.out.println("  File: " + p.getFileName()));
        }

        // File attributes
        BasicFileAttributes attrs = Files.readAttributes(tmpFile, BasicFileAttributes.class);
        System.out.println("Size: " + attrs.size() + " bytes");
        System.out.println("Created: " + attrs.creationTime());

        // WatchService — monitors filesystem events
        try (WatchService watcher = FileSystems.getDefault().newWatchService()) {
            tmpDir.register(watcher,
                StandardWatchEventKinds.ENTRY_CREATE,
                StandardWatchEventKinds.ENTRY_MODIFY,
                StandardWatchEventKinds.ENTRY_DELETE);

            // Create a new file to trigger an event
            Files.writeString(tmpDir.resolve("trigger.txt"), "event");

            WatchKey key = watcher.poll(2, java.util.concurrent.TimeUnit.SECONDS);
            if (key != null) {
                for (WatchEvent<?> event : key.pollEvents()) {
                    System.out.println("Event: " + event.kind() + " → " + event.context());
                }
                key.reset(); // MUST reset to receive further events
            }
        }

        // Cleanup
        Files.walk(tmpDir).sorted(java.util.Comparator.reverseOrder())
             .forEach(p -> { try { Files.delete(p); } catch (IOException ignored) {} });
    }
}

import java.io.*;
import java.nio.file.*;
import java.util.*;

public class ScannerPrintWriter {

    record Person(String name, int age, String city) {}

    public static void main(String[] args) throws IOException {
        Path tmpDir = Files.createTempDirectory("scanner_demo");

        // ── Write CSV with PrintWriter ─────────────────────────────────
        Path csvFile = tmpDir.resolve("people.csv");
        try (PrintWriter pw = new PrintWriter(
                new BufferedWriter(new FileWriter(csvFile.toFile())))) {
            pw.println("name,age,city");  // header
            pw.printf("%s,%d,%s%n", "Alice", 30, "Delhi");
            pw.printf("%s,%d,%s%n", "Bob",   25, "Mumbai");
            pw.printf("%s,%d,%s%n", "Carol", 28, "Bangalore");
        } // auto-flush on close

        // ── Read CSV with Scanner ──────────────────────────────────────
        List<Person> people = new ArrayList<>();
        try (Scanner sc = new Scanner(csvFile)) {
            sc.nextLine(); // skip header
            sc.useDelimiter(",|\n|\r\n"); // split on comma OR newline
            while (sc.hasNext()) {
                String name = sc.next().trim();
                if (name.isEmpty()) continue;
                int    age  = sc.nextInt();
                String city = sc.next().trim();
                people.add(new Person(name, age, city));
            }
        }
        people.forEach(System.out::println);
        // Person[name=Alice, age=30, city=Delhi]
        // Person[name=Bob,   age=25, city=Mumbai]
        // Person[name=Carol, age=28, city=Bangalore]

        // ── Scanner from String — tokenizer ───────────────────────────
        String data = "42 3.14 hello true";
        Scanner sc = new Scanner(data);
        System.out.println(sc.nextInt());    // 42
        System.out.println(sc.nextDouble()); // 3.14
        System.out.println(sc.next());       // hello
        System.out.println(sc.nextBoolean());// true
        sc.close();

        // ── PrintWriter formatted table ────────────────────────────────
        PrintWriter pw = new PrintWriter(System.out, true); // autoFlush
        pw.printf("%-15s %5s %15s%n", "Name", "Age", "City");
        pw.printf("%-15s %5s %15s%n", "-".repeat(15), "-----", "-".repeat(15));
        for (Person p : people)
            pw.printf("%-15s %5d %15s%n", p.name(), p.age(), p.city());

        // Cleanup
        Files.walk(tmpDir).sorted(Comparator.reverseOrder())
             .forEach(path -> { try { Files.delete(path); } catch (IOException ignored) {} });
    }
}

import java.io.*;
import java.nio.file.*;
import java.util.*;

public class SerializationDemo {

    // Version 1 of the class
    static class UserV1 implements Serializable {
        private static final long serialVersionUID = 1L; // explicit version

        private String   username;
        private String   email;
        private transient String password; // NOT serialized — security
        private transient int    cachedHash; // NOT serialized — derived value
        private List<String> roles;

        UserV1(String username, String email, String password, List<String> roles) {
            this.username = username;
            this.email    = email;
            this.password = password;
            this.roles    = new ArrayList<>(roles);
            this.cachedHash = Objects.hash(username, email);
        }

        // Custom writeObject — called during serialization
        private void writeObject(ObjectOutputStream oos) throws IOException {
            oos.defaultWriteObject(); // write all non-transient fields
            oos.writeInt(roles.size()); // extra custom data
            System.out.println("Custom writeObject called");
        }

        // Custom readObject — called during deserialization
        private void readObject(ObjectInputStream ois) throws IOException, ClassNotFoundException {
            ois.defaultReadObject(); // restore all non-transient fields
            int extraSize = ois.readInt(); // read custom data
            this.cachedHash = Objects.hash(username, email); // recalculate transient
            System.out.println("Custom readObject called, extra: " + extraSize);
        }

        @Override public String toString() {
            return "User{" + username + ", roles=" + roles +
                   ", pwd=" + (password != null ? "[SET]" : "[NULL-transient]") +
                   ", hash=" + cachedHash + "}";
        }
    }

    public static void main(String[] args) throws Exception {
        Path file = Files.createTempFile("user_serial", ".bin");

        UserV1 original = new UserV1("alice", "alice@ex.com", "s3cret",
                                     List.of("USER", "EDITOR"));
        System.out.println("Before: " + original);

        // Serialize
        try (ObjectOutputStream oos = new ObjectOutputStream(
                new BufferedOutputStream(new FileOutputStream(file.toFile())))) {
            oos.writeObject(original);
        }

        // Deserialize
        UserV1 restored;
        try (ObjectInputStream ois = new ObjectInputStream(
                new BufferedInputStream(new FileInputStream(file.toFile())))) {
            restored = (UserV1) ois.readObject();
        }

        System.out.println("After:  " + restored);
        // password is null — transient not serialized
        // cachedHash is recalculated in readObject

        Files.delete(file);
    }
}

import java.io.*;
import java.nio.*;
import java.nio.channels.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;

public class NIOChannels {

    public static void main(String[] args) throws IOException {
        Path tmpDir = Files.createTempDirectory("nio_channels");
        Path src    = tmpDir.resolve("source.txt");
        Path dst    = tmpDir.resolve("dest.txt");

        Files.writeString(src, "Hello NIO Channels and ByteBuffer!");

        // ── FileChannel + ByteBuffer — explicit buffer management ──────
        try (FileChannel inCh  = FileChannel.open(src, StandardOpenOption.READ);
             FileChannel outCh = FileChannel.open(dst,
                 StandardOpenOption.CREATE, StandardOpenOption.WRITE)) {

            ByteBuffer buf = ByteBuffer.allocate(1024); // on-heap buffer

            while (inCh.read(buf) != -1) {
                buf.flip();           // switch from write mode → read mode
                while (buf.hasRemaining()) {
                    outCh.write(buf); // write remaining bytes
                }
                buf.clear();          // switch back to write mode
            }
        }
        System.out.println("Copied: " + Files.readString(dst));

        // ── Channel-to-channel transfer — zero copy ────────────────────
        Path dst2 = tmpDir.resolve("dest2.txt");
        try (FileChannel inCh  = FileChannel.open(src, StandardOpenOption.READ);
             FileChannel outCh = FileChannel.open(dst2,
                 StandardOpenOption.CREATE, StandardOpenOption.WRITE)) {
            inCh.transferTo(0, inCh.size(), outCh); // OS-level copy — no user-space buffer
        }
        System.out.println("Zero-copy: " + Files.readString(dst2));

        // ── MappedByteBuffer — file backed by virtual memory ──────────
        Path largeFile = tmpDir.resolve("large.txt");
        // Write a file with indexed content
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 1000; i++) sb.append(String.format("Record %04d\n", i));
        Files.writeString(largeFile, sb.toString());

        try (FileChannel fc = FileChannel.open(largeFile, StandardOpenOption.READ)) {
            MappedByteBuffer mbb = fc.map(
                FileChannel.MapMode.READ_ONLY, 0, fc.size());

            // Random access: jump to any position without reading from start
            mbb.position(0);
            byte[] header = new byte[11]; // "Record 0000"
            mbb.get(header);
            System.out.println("First record: " + new String(header, StandardCharsets.UTF_8));

            // Search: scan through the memory-mapped file
            int count = 0;
            mbb.rewind();
            String content = StandardCharsets.UTF_8.decode(mbb).toString();
            for (int i = 0; i < content.length() - 1; i++)
                if (content.charAt(i) == 'R') count++;
            System.out.println("Record count: " + count); // 1000
        }

        // Cleanup
        Files.walk(tmpDir).sorted(java.util.Comparator.reverseOrder())
             .forEach(p -> { try { Files.delete(p); } catch (IOException ignored) {} });
    }
}

