import java.io.*;
import java.nio.file.*;
import java.util.*;
import java.util.concurrent.*;

public class Q8 {
    public static List<String> watchForChanges(String dirPath, long timeoutMs)
            throws IOException, InterruptedException {
        List<String> created = new ArrayList<>();
        try (WatchService watcher = FileSystems.getDefault().newWatchService()) {
            Path dir = Path.of(dirPath);
            dir.register(watcher, StandardWatchEventKinds.ENTRY_CREATE);
            long deadline = System.currentTimeMillis() + timeoutMs;
            while (System.currentTimeMillis() < deadline) {
                long remaining = deadline - System.currentTimeMillis();
                if (remaining <= 0) break;
                WatchKey key = watcher.poll(remaining, TimeUnit.MILLISECONDS);
                if (key == null) break;
                for (WatchEvent<?> event : key.pollEvents()) {
                    if (event.kind() == StandardWatchEventKinds.ENTRY_CREATE) {
                        created.add(event.context().toString());
                    }
                }
                key.reset(); // MUST reset
            }
        }
        return created;
    }
    public static void main(String[] args) throws Exception {
        Path dir = Files.createTempDirectory("q8");
        List<String>[] result = new List[]{null};
        Thread t = new Thread(() -> {
            try { result[0] = watchForChanges(dir.toString(), 2000); }
            catch (Exception e) { result[0] = List.of(); }
        });
        t.start(); Thread.sleep(100);
        Files.writeString(dir.resolve("hello.txt"), "hi");
        Files.writeString(dir.resolve("world.txt"), "there");
        t.join();
