import java.util.*;

public class Q11 {
    static class FileLRUCache {
        private final Path dir;
        private final LinkedHashMap<String, Boolean> lru;

        FileLRUCache(int capacity) throws IOException {
            this.dir = Files.createTempDirectory("lru_cache");
            this.lru = new LinkedHashMap<>(capacity, 0.75f, true) {
                protected boolean removeEldestEntry(Map.Entry<String, Boolean> eldest) {
                    if (size() > capacity) {
                        try { Files.deleteIfExists(dir.resolve(eldest.getKey())); }
                        catch (IOException ignored) {}
                        return true;
                    }
                    return false;
                }
            };
        }

        public void put(String key, String value) throws IOException {
            Files.writeString(dir.resolve(key), value);
            lru.put(key, Boolean.TRUE);
        }

        public String get(String key) throws IOException {
            if (!lru.containsKey(key)) return null;
            lru.get(key); // touch — moves to most-recently-used
            return Files.readString(dir.resolve(key));
        }

        public void cleanup() throws IOException {
            Files.walk(dir).sorted(Comparator.reverseOrder())
                 .forEach(p -> { try { Files.delete(p); } catch (IOException ignored) {} });
        }
    }

    public static void main(String[] args) throws Exception {
        FileLRUCache cache = new FileLRUCache(3);
        cache.put("a", "Apple"); cache.put("b", "Banana"); cache.put("c", "Cherry");
        System.out.println(cache.get("a")); // Apple
        cache.put("d", "Date");
        System.out.println(cache.get("b")); // null
        System.out.println(cache.get("d")); // Date
        cache.cleanup();
