import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.function.*;

public class Q13 {
    public static List<String> tailFile(String filePath, int n) throws IOException {
        Deque<String> last = new ArrayDeque<>(n + 1);
        try (BufferedReader br = Files.newBufferedReader(Path.of(filePath))) {
            String line;
            while ((line = br.readLine()) != null) {
                last.addLast(line);
                if (last.size() > n) last.removeFirst();
            }
        }
        return new ArrayList<>(last);
    }

    public static void tailFollow(String filePath, Consumer<String> onLine, long durationMs)
            throws IOException, InterruptedException {
        Path path = Path.of(filePath);
        long[] pos = {Files.size(path)}; // track last read position
        try (WatchService watcher = FileSystems.getDefault().newWatchService()) {
            path.getParent().register(watcher, StandardWatchEventKinds.ENTRY_MODIFY);
            long deadline = System.currentTimeMillis() + durationMs;
            while (System.currentTimeMillis() < deadline) {
                long remaining = deadline - System.currentTimeMillis();
                WatchKey key = watcher.poll(Math.max(remaining, 0), TimeUnit.MILLISECONDS);
                if (key == null) break;
                for (WatchEvent<?> event : key.pollEvents()) {
                    if (event.context().toString().equals(path.getFileName().toString())) {
                        // Read only new content since last position
                        try (RandomAccessFile raf = new RandomAccessFile(filePath, "r")) {
                            raf.seek(pos[0]);
                            String line;
                            while ((line = raf.readLine()) != null) {
                                onLine.accept(new String(line.getBytes(StandardCharsets.ISO_8859_1),
                                    StandardCharsets.UTF_8));
                            }
                            pos[0] = raf.getFilePointer();
                        }
                    }
                }
                key.reset();
            }
        }
    }

    public static void main(String[] args) throws Exception {
        Path tmp = Files.createTempFile("q13",".txt");
        for (int i = 1; i <= 10; i++)
            Files.writeString(tmp, "Line "+i+"\n", StandardOpenOption.APPEND);
        System.out.println(tailFile(tmp.toString(), 3));
        List<String> live = new ArrayList<>();
        Thread t = new Thread(() -> {
            try { tailFollow(tmp.toString(), live::add, 2000); }
            catch (Exception ignored) {}
        });
        t.start(); Thread.sleep(200);
        Files.writeString(tmp, "Line 11\n", StandardOpenOption.APPEND);
        Files.writeString(tmp, "Line 12\n", StandardOpenOption.APPEND);
        t.join();
        System.out.println(live);
        Files.delete(tmp);
    }
}

