public class Q14 {
    private static final int CHUNK = 4096;

    public static List<String> binaryDiff(String file1, String file2) throws IOException {
        List<String> diffs = new ArrayList<>();
        try (FileChannel ch1 = FileChannel.open(Path.of(file1), StandardOpenOption.READ);
             FileChannel ch2 = FileChannel.open(Path.of(file2), StandardOpenOption.READ)) {
            long s1 = ch1.size(), s2 = ch2.size();
            if (s1 != s2)
                diffs.add(String.format("file1 size=%d, file2 size=%d", s1, s2));
            long offset = 0;
            ByteBuffer b1 = ByteBuffer.allocate(CHUNK);
            ByteBuffer b2 = ByteBuffer.allocate(CHUNK);
            while (offset < Math.min(s1, s2)) {
                b1.clear(); b2.clear();
                int r1 = ch1.read(b1); int r2 = ch2.read(b2);
                int compare = Math.min(r1, r2);
                b1.flip(); b2.flip();
                for (int i = 0; i < compare; i++) {
                    byte v1 = b1.get(), v2 = b2.get();
                    if (v1 != v2)
                        diffs.add(String.format("offset 0x%x: file1=%02x file2=%02x",
                            offset + i, v1 & 0xFF, v2 & 0xFF));
                }
                offset += compare;
            }
        }
        return diffs;
    }
    public static void main(String[] args) throws Exception {
        Path f1 = Files.createTempFile("q14a",".bin");
        Path f2 = Files.createTempFile("q14b",".bin");
        Files.write(f1, new byte[]{0x48,0x65,0x6C,0x6C,0x6F});
        Files.write(f2, new byte[]{0x48,0x65,0x6C,0x70,0x6F});
        binaryDiff(f1.toString(), f2.toString()).forEach(System.out::println);
        Files.delete(f1); Files.delete(f2);
