import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.util.*;
import java.util.zip.*;

public class Q19 {
    public static void createZip(Map<String, String> entries, String zipPath)
            throws IOException {
        try (ZipOutputStream zos = new ZipOutputStream(
                new BufferedOutputStream(new FileOutputStream(zipPath)))) {
            zos.setMethod(ZipOutputStream.DEFLATED);
            for (Map.Entry<String, String> e : entries.entrySet()) {
                zos.putNextEntry(new ZipEntry(e.getKey()));
                zos.write(e.getValue().getBytes(StandardCharsets.UTF_8));
                zos.closeEntry();
            }
        }
    }

    public static Map<String, String> readZip(String zipPath) throws IOException {
        Map<String, String> result = new LinkedHashMap<>();
        try (ZipInputStream zis = new ZipInputStream(
                new BufferedInputStream(new FileInputStream(zipPath)))) {
            ZipEntry entry;
            while ((entry = zis.getNextEntry()) != null) {
                if (!entry.isDirectory()) {
                    byte[] bytes = zis.readAllBytes();
                    result.put(entry.getName(),
                        new String(bytes, StandardCharsets.UTF_8));
                }
                zis.closeEntry();
            }
        }
        return result;
    }

    public static void main(String[] args) throws Exception {
        Path zip = Files.createTempFile("q19",".zip");
        var entries = new LinkedHashMap<String, String>();
        entries.put("hello.txt", "Hello World");
        entries.put("data.json", "{\"key\":\"value\"}");
        createZip(entries, zip.toString());
        var read = readZip(zip.toString());
        System.out.println(read.get("hello.txt"));
        System.out.println(read.get("data.json"));
        System.out.println(read.size());
        Files.delete(zip);
    }
}

