import java.io.*;
import java.net.*;
import java.nio.*;
import java.nio.channels.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.util.*;

public class Q20 {
    static class FileServer {
        private final int port;
        private final Path rootDir;
        volatile boolean running = true;
        int actualPort;

        FileServer(int port, Path rootDir) { this.port=port; this.rootDir=rootDir; }

        public void start() throws IOException {
            try (Selector selector = Selector.open();
                 ServerSocketChannel ssc = ServerSocketChannel.open()) {
                ssc.configureBlocking(false);
                ssc.bind(new InetSocketAddress(port));
                actualPort = ((InetSocketAddress) ssc.getLocalAddress()).getPort();
                ssc.register(selector, SelectionKey.OP_ACCEPT);

                while (running) {
                    int ready = selector.select(500); // 500ms timeout
                    if (ready == 0) continue;

                    Iterator<SelectionKey> keys = selector.selectedKeys().iterator();
                    while (keys.hasNext()) {
                        SelectionKey key = keys.next();
                        keys.remove();

                        if (key.isAcceptable()) {
                            SocketChannel client = ssc.accept();
                            if (client != null) {
                                client.configureBlocking(false);
                                client.register(selector, SelectionKey.OP_READ);
                            }
                        } else if (key.isReadable()) {
                            SocketChannel client = (SocketChannel) key.channel();
                            ByteBuffer buf = ByteBuffer.allocate(256);
                            int read = client.read(buf);
                            if (read > 0) {
                                buf.flip();
                                String filename = StandardCharsets.UTF_8
                                    .decode(buf).toString().trim();
                                Path file = rootDir.resolve(filename);
                                if (Files.exists(file) && Files.isRegularFile(file)) {
                                    try (FileChannel fc = FileChannel.open(file,
                                            StandardOpenOption.READ)) {
                                        fc.transferTo(0, fc.size(), client);
                                    }
                                } else {
                                    client.write(ByteBuffer.wrap(
                                        "NOT FOUND".getBytes(StandardCharsets.UTF_8)));
                                }
                                client.close();
                            }
                        }
                    }
                }
            }
        }

        public void stop() { running = false; }
    }

    public static void main(String[] args) throws Exception {
        Path dir = Files.createTempDirectory("q20");
        Files.writeString(dir.resolve("hello.txt"), "Hello from NIO server!");
        FileServer server = new FileServer(0, dir);
        Thread t = new Thread(() -> { try { server.start(); } catch (IOException ignored) {} });
        t.start();
        Thread.sleep(200);
        // Client
        try (SocketChannel client = SocketChannel.open(
                new InetSocketAddress("localhost", server.actualPort))) {
            client.write(ByteBuffer.wrap("hello.txt\n".getBytes()));
            ByteBuffer resp = ByteBuffer.allocate(1024);
            Thread.sleep(200);
            client.read(resp);
            resp.flip();
            System.out.println(StandardCharsets.UTF_8.decode(resp).toString().trim());
            // Hello from NIO server!
        }
        server.stop(); t.join(1000);
        Files.walk(dir).sorted(Comparator.reverseOrder())
             .forEach(p -> { try{Files.delete(p);}catch(IOException e){} });
    }
}
